@import 'tailwindcss';

/* Import Editor.js styles */
@import './editor.css';

/* ──────────────────────────────────────────────────────────────────────
   Tailwind v4 theme wiring.
   The design tokens defined in :root / .dark below are exposed to Tailwind
   as semantic color utilities (bg-card, text-muted-foreground, border-border,
   bg-popover, …) via @theme inline. `inline` keeps the generated utilities
   referencing var(--token) at runtime, so the .dark overrides take effect.
   Without this block these utilities generate NO css and dark mode is inert. */
@theme inline {
  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --color-card: var(--card);
  --color-card-foreground: var(--card-foreground);
  --color-popover: var(--popover);
  --color-popover-foreground: var(--popover-foreground);
  --color-primary: var(--primary);
  --color-primary-foreground: var(--primary-foreground);
  --color-secondary: var(--secondary);
  --color-secondary-foreground: var(--secondary-foreground);
  --color-muted: var(--muted);
  --color-muted-foreground: var(--muted-foreground);
  --color-accent: var(--accent);
  --color-accent-foreground: var(--accent-foreground);
  --color-destructive: var(--destructive);
  --color-destructive-foreground: var(--destructive-foreground);
  --color-success: var(--success);
  --color-success-foreground: var(--success-foreground);
  --color-warning: var(--warning);
  --color-warning-foreground: var(--warning-foreground);
  --color-info: var(--info);
  --color-info-foreground: var(--info-foreground);
  --color-border: var(--border);
  --color-input: var(--input);
  --color-ring: var(--ring);
  --color-chart-1: var(--chart-1);
  --color-chart-2: var(--chart-2);
  --color-chart-3: var(--chart-3);
  --color-chart-4: var(--chart-4);
  --color-chart-5: var(--chart-5);
  --color-sidebar: var(--sidebar);
  --color-sidebar-foreground: var(--sidebar-foreground);
  --color-sidebar-primary: var(--sidebar-primary);
  --color-sidebar-primary-foreground: var(--sidebar-primary-foreground);
  --color-sidebar-accent: var(--sidebar-accent);
  --color-sidebar-accent-foreground: var(--sidebar-accent-foreground);
  --color-sidebar-border: var(--sidebar-border);
  --color-sidebar-ring: var(--sidebar-ring);
  --radius-lg: var(--radius);
  --radius-md: calc(var(--radius) - 2px);
  --radius-sm: calc(var(--radius) - 4px);
}

@layer base {
  :root {
    --radius: 0.625rem;
    --background: oklch(1 0 0);
    --foreground: oklch(0.145 0 0);
    --card: oklch(1 0 0);
    --card-foreground: oklch(0.145 0 0);
    --popover: oklch(1 0 0);
    --popover-foreground: oklch(0.145 0 0);
    --primary: oklch(0.205 0 0);
    --primary-foreground: oklch(0.985 0 0);
    --secondary: oklch(0.97 0 0);
    --secondary-foreground: oklch(0.205 0 0);
    --muted: oklch(0.97 0 0);
    --muted-foreground: oklch(0.556 0 0);
    --accent: oklch(0.97 0 0);
    --accent-foreground: oklch(0.205 0 0);
    --destructive: oklch(0.577 0.245 27.325);
    --destructive-foreground: oklch(0.985 0 0);
    --success: oklch(0.648 0.15 152);
    --success-foreground: oklch(0.985 0 0);
    --warning: oklch(0.79 0.16 78);
    --warning-foreground: oklch(0.205 0 0);
    --info: oklch(0.62 0.18 256);
    --info-foreground: oklch(0.985 0 0);
    --border: oklch(0.922 0 0);
    --input: oklch(0.922 0 0);
    --ring: oklch(0.708 0 0);
    --chart-1: oklch(0.646 0.222 41.116);
    --chart-2: oklch(0.6 0.118 184.704);
    --chart-3: oklch(0.398 0.07 227.392);
    --chart-4: oklch(0.828 0.189 84.429);
    --chart-5: oklch(0.769 0.188 70.08);
    --sidebar: oklch(0.985 0 0);
    --sidebar-foreground: oklch(0.145 0 0);
    --sidebar-primary: oklch(0.205 0 0);
    --sidebar-primary-foreground: oklch(0.985 0 0);
    --sidebar-accent: oklch(0.97 0 0);
    --sidebar-accent-foreground: oklch(0.205 0 0);
    --sidebar-border: oklch(0.922 0 0);
    --sidebar-ring: oklch(0.708 0 0);
  }

  .dark {
    --background: oklch(0.145 0 0);
    --foreground: oklch(0.985 0 0);
    --card: oklch(0.205 0 0);
    --card-foreground: oklch(0.985 0 0);
    --popover: oklch(0.205 0 0);
    --popover-foreground: oklch(0.985 0 0);
    --primary: oklch(0.922 0 0);
    --primary-foreground: oklch(0.205 0 0);
    --secondary: oklch(0.269 0 0);
    --secondary-foreground: oklch(0.985 0 0);
    --muted: oklch(0.269 0 0);
    --muted-foreground: oklch(0.708 0 0);
    --accent: oklch(0.269 0 0);
    --accent-foreground: oklch(0.985 0 0);
    --destructive: oklch(0.704 0.191 22.216);
    --destructive-foreground: oklch(0.985 0 0);
    --success: oklch(0.696 0.16 152);
    --success-foreground: oklch(0.145 0 0);
    --warning: oklch(0.82 0.16 80);
    --warning-foreground: oklch(0.145 0 0);
    --info: oklch(0.707 0.16 256);
    --info-foreground: oklch(0.145 0 0);
    --border: oklch(1 0 0 / 10%);
    --input: oklch(1 0 0 / 15%);
    --ring: oklch(0.556 0 0);
    --chart-1: oklch(0.488 0.243 264.376);
    --chart-2: oklch(0.696 0.17 162.48);
    --chart-3: oklch(0.769 0.188 70.08);
    --chart-4: oklch(0.627 0.265 303.9);
    --chart-5: oklch(0.645 0.246 16.439);
    --sidebar: oklch(0.205 0 0);
    --sidebar-foreground: oklch(0.985 0 0);
    --sidebar-primary: oklch(0.488 0.243 264.376);
    --sidebar-primary-foreground: oklch(0.985 0 0);
    --sidebar-accent: oklch(0.269 0 0);
    --sidebar-accent-foreground: oklch(0.985 0 0);
    --sidebar-border: oklch(1 0 0 / 10%);
    --sidebar-ring: oklch(0.556 0 0);
  }

  * {
    border-color: var(--border);
  }

  body {
    background-color: var(--background);
    color: var(--foreground);
    font-family:
      system-ui,
      -apple-system,
      BlinkMacSystemFont,
      'Segoe UI',
      Roboto,
      'Helvetica Neue',
      Arial,
      'Noto Sans',
      sans-serif;
    min-height: 100vh;
    overflow-x: hidden;
  }

  #root {
    min-height: 100vh;
    display: flex;
    flex-direction: column;
  }

  /* Animated dash for dotted edges */
  @keyframes dash {
    to {
      stroke-dashoffset: -10px;
    }
  }
}

/* React Flow specific styles */
.react-flow__node {
  font-family: inherit;
}

.react-flow__edge {
  stroke-width: 2;
}

.react-flow__edge.react-flow__edge-path {
  stroke: var(--border);
}

.react-flow__edge.selected .react-flow__edge-path {
  stroke: var(--primary);
}

/* ================================================================
   DIALOG / MODAL / OVERLAY OPACITY + Z-INDEX
   ----------------------------------------------------------------
   These rules guarantee opaque, correctly-stacked overlays. They use
   theme tokens (var(--background)/var(--popover)/var(--border)) so they
   work in BOTH light and dark mode. (Previously hardcoded `white`, which
   broke dark mode.) Z-index hierarchy:
     Modal overlays: 1000 · Modal content: 1001
     Dropdowns/Popovers: 9999 · Toasts: 9999
   ================================================================ */

/* All dialog overlays */
[data-slot='dialog-overlay'],
[data-slot='alert-dialog-overlay'],
[role='presentation'][data-state='open'] {
  z-index: 1000 !important;
  background-color: rgba(0, 0, 0, 0.5) !important;
  opacity: 1 !important;
}

/* Sheet overlay */
[data-slot='sheet-overlay'] {
  z-index: 999 !important;
  background-color: rgba(0, 0, 0, 0.3) !important;
  opacity: 1 !important;
  pointer-events: none !important;
}

/* All dialog content - opaque themed backgrounds */
[data-slot='dialog-content'],
[data-slot='alert-dialog-content'],
[data-slot='sheet-content'],
[role='dialog'] {
  z-index: 1001 !important;
  background: var(--background) !important;
  color: var(--foreground) !important;
  border: 1px solid var(--border) !important;
  box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.25) !important;
  opacity: 1 !important;
}

/* All dropdown/popover/command content - opaque themed backgrounds */
[data-slot='select-content'],
[data-slot='popover-content'],
[data-slot='dropdown-menu-content'],
[data-slot='command'] {
  z-index: 9999 !important;
  background: var(--popover) !important;
  color: var(--popover-foreground) !important;
  border: 1px solid var(--border) !important;
  box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.25) !important;
  opacity: 1 !important;
  pointer-events: auto !important;
}

/* Sheet specific - force solid themed background + correct placement */
[data-slot='sheet-content'],
.sheet-content {
  z-index: 1002 !important;
  background: var(--background) !important;
  color: var(--foreground) !important;
  border: 1px solid var(--border) !important;
  box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.5) !important;
  opacity: 1 !important;
  position: fixed !important;
  top: 0 !important;
  right: 0 !important;
  height: 100vh !important;
  transform: translateX(0) !important;
  pointer-events: auto !important;
}

/* Override body pointer-events for sheet content */
body[data-scroll-locked='1'] [data-slot='sheet-content'],
body[data-scroll-locked='1'] .sheet-content {
  pointer-events: auto !important;
}

/* Force all sheet children to be interactive */
[data-slot='sheet-content'] *,
.sheet-content * {
  pointer-events: auto !important;
}

[data-slot='sheet-content'] [data-slot='sheet-title'] {
  color: var(--foreground) !important;
}

[data-slot='sheet-content'] [data-slot='sheet-description'] {
  color: var(--muted-foreground) !important;
}

/* Search dialog specific */
.quick-search-dialog [data-slot='dialog-content'] {
  background: var(--background) !important;
  color: var(--foreground) !important;
  border: 1px solid var(--border) !important;
  box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.5) !important;
}

/* Command palette specific */
[data-slot='command'] {
  background: var(--popover) !important;
  color: var(--popover-foreground) !important;
}

/* Toaster components */
[data-sonner-toaster] {
  z-index: 9999 !important;
}

[data-sonner-toast] {
  z-index: 9999 !important;
}

/* ReactFlow specific styling */
.react-flow__node {
  z-index: 2 !important;
}

.react-flow__edge {
  z-index: 1 !important;
}

/* Custom React Flow node styles */
.react-flow__node-metric {
  background: var(--card) !important;
  border: 1px solid var(--border) !important;
}

/* ── Group focus mode ───────────────────────────────────────────────
   When a group is "focused" from the Groups panel, non-member nodes and
   edges are dimmed to faint context so the user can zoom into one objective.
   Edges must be dimmed via the edge group className because DynamicEdge
   hardcodes its own path opacity (inline edge style is overridden). */
.react-flow__node.rf-node-dimmed {
  opacity: 0.15 !important;
  filter: grayscale(0.35);
  transition: opacity 0.25s ease, filter 0.25s ease;
  pointer-events: none;
}
.react-flow__edge.rf-edge-dimmed {
  opacity: 0.1 !important;
  transition: opacity 0.25s ease;
}
.react-flow__node:not(.rf-node-dimmed),
.react-flow__edge:not(.rf-edge-dimmed) {
  transition: opacity 0.25s ease;
}

