48	
49	const evidenceTypeOptions = [
50	  {
51	    value: 'Experiment',
52	    icon: FlaskConical,
53	    color: 'bg-blue-50 text-blue-700',
54	  },
55	  { value: 'Analysis', icon: FileText, color: 'bg-green-50 text-green-700' },
56	  { value: 'Notebook', icon: BookOpen, color: 'bg-purple-50 text-purple-700' },
57	  {
58	    value: 'External Research',
59	    icon: Globe,
60	    color: 'bg-orange-50 text-orange-700',
61	  },
62	  { value: 'User Interview', icon: Users, color: 'bg-pink-50 text-pink-700' },
63	];
64	
65	export default function EvidenceRepositoryPage() {
66	  const { canvas } = useCanvasStore();
67	  const {
68	    evidence,
69	    addEvidence,
70	    updateEvidence,
71	    deleteEvidence,
72	    duplicateEvidence,
73	  } = useEvidenceStore();
74	
75	  const [searchTerm, setSearchTerm] = useState('');
76	  const [selectedType, setSelectedType] = useState<string>('all');
77	  const [selectedOwner, setSelectedOwner] = useState<string>('all');
78	  const [isEditorOpen, setIsEditorOpen] = useState(false);
79	  const [isFullscreen, setIsFullscreen] = useState(false);
80	  const [selectedEvidence, setSelectedEvidence] = useState<EvidenceItem | null>(
81	    null
82	  );
83	
84	  // Combine standalone evidence with relationship evidence
85	  const allEvidence = useMemo(() => {
86	    const evidenceMap = new Map<
87	      string,
88	      EvidenceItem & { relationshipCount: number; relationships: string[] }
89	    >();
90	
91	    // Add standalone evidence from evidence store
92	    evidence.forEach((item) => {
93	      evidenceMap.set(item.id, {
94	        ...item,
95	        relationshipCount: 0,
96	        relationships: [],
97	      });
98	    });
99	
100	    // Add evidence from relationships
101	    if (canvas?.edges) {
102	      canvas.edges.forEach((relationship) => {
103	        relationship.evidence?.forEach((relationshipEvidence) => {
104	          const existing = evidenceMap.get(relationshipEvidence.id);
105	          if (existing) {
106	            existing.relationshipCount++;
107	            existing.relationships.push(relationship.id);
108	          } else {
109	            evidenceMap.set(relationshipEvidence.id, {
110	              ...relationshipEvidence,
111	              relationshipCount: 1,
112	              relationships: [relationship.id],
113	            });
114	          }
115	        });
116	      });
117	    }
118	
119	    return Array.from(evidenceMap.values());
120	  }, [evidence, canvas?.edges]);
121	
122	  // Get unique owners for filtering
123	  const uniqueOwners = useMemo(() => {
124	    return Array.from(new Set(allEvidence.map((e) => e.owner).filter(Boolean)));
125	  }, [allEvidence]);
126	
127	  // Filter evidence based on search and filters
128	  const filteredEvidence = useMemo(() => {
129	    return allEvidence.filter((evidence) => {
130	      const matchesSearch =
131	        evidence.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
132	        evidence.summary.toLowerCase().includes(searchTerm.toLowerCase()) ||
133	        evidence.owner.toLowerCase().includes(searchTerm.toLowerCase());
134	
135	      const matchesType =
136	        selectedType === 'all' || evidence.type === selectedType;
137	      const matchesOwner =
138	        selectedOwner === 'all' || evidence.owner === selectedOwner;
139	
140	      return matchesSearch && matchesType && matchesOwner;
141	    });
142	  }, [allEvidence, searchTerm, selectedType, selectedOwner]);
143	
144	  const handleCreateEvidence = () => {
145	    setSelectedEvidence(null);
146	    setIsEditorOpen(true);
147	  };
148	
149	  const handleEditEvidence = (evidence: EvidenceItem) => {
150	    setSelectedEvidence(evidence);
151	    setIsEditorOpen(true);
152	  };
153	
154	  const handleSaveEvidence = (
155	    evidence: EvidenceItem,
156	    options?: { autoSave?: boolean }
157	  ) => {
158	    if (selectedEvidence) {
159	      // Update existing evidence
160	      updateEvidence(selectedEvidence.id, evidence);
161	    } else {
162	      // Create new evidence
163	      addEvidence(evidence);
164	    }
165	
166	    // Only close dialog on manual save, not auto-save
167	    if (!options?.autoSave) {
168	      setIsEditorOpen(false);
169	      setSelectedEvidence(null);
170	    }
