import { useSourcesStore } from '@/features/sources/stores/useSourcesStore';
import { useSourceFiltering } from '@/shared/hooks/useSourceFiltering';

// Dialog components (moved under features/sources/components/dialogs)
import ApiConnectionDialog from '@/features/sources/components/dialogs/ApiConnectionDialog';
import DataSourceDialog from '@/features/sources/components/dialogs/DataSourceDialog';
import ExportDialog, {
  type ExportOptions,
} from '@/features/sources/components/dialogs/ExportDialog';
import GovernancePolicyDialog from '@/features/sources/components/dialogs/GovernancePolicyDialog';
import MonitoringSettingsDialog, {
  type MonitoringSettings,
} from '@/features/sources/components/dialogs/MonitoringSettingsDialog';

// Tab components

type InstrumentationStatus = 'Planned' | 'Instrumented' | 'Needs QA' | 'Live';

export default function SourcePage() {
  const [activeTab, setActiveTab] = useState<TabType>('sources');
  const [searchQuery, setSearchQuery] = useState('');
  const [statusFilter, setStatusFilter] = useState<StatusFilter>('all');
  const [systemFilter, setSystemFilter] = useState('all');

  // State from store
  const {
    dataSources,
    apiConnections,
    governancePolicies,
    // CRUD operations
    createDataSource,
    updateDataSource,
    deleteDataSource,
    createApiConnection,
    updateApiConnection,
    deleteApiConnection,
    createGovernancePolicy,
    updateGovernancePolicy,
    deleteGovernancePolicy,
    // Utility operations
    exportData,
    refreshMonitoring,
    loadAllData,
  } = useSourcesStore();

import { Badge } from '@/shared/components/ui/badge';
import { Button } from '@/shared/components/ui/button';
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from '@/shared/components/ui/card';
import {
  DropdownMenu,
